# Skeptic re-check — instruction vs starter defect
class TokenBucket:
    def __init__(self, rate):
        self.tokens = rate
    def allow(self):
        if self.tokens >= 1:
            self.tokens -= 1
            return True
        return False
b = TokenBucket(3)
allows = [b.allow() for _ in range(3)]
print('ok')

